<script setup>defineProps({ open: Boolean, title: String, message: String, busy: Boolean }); defineEmits(['confirm', 'cancel'])</script>
<template><div v-if="open" class="modal-backdrop" @click.self="$emit('cancel')"><section class="modal" role="dialog" aria-modal="true" :aria-label="title"><div class="modal-icon">!</div><h2>{{ title }}</h2><p>{{ message }}</p><div class="modal-actions"><button class="button button-ghost" :disabled="busy" @click="$emit('cancel')">取消</button><button class="button button-danger" :disabled="busy" @click="$emit('confirm')">{{ busy ? '處理中…' : '確認刪除' }}</button></div></section></div></template>
